app.get('/users', (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    ...
  ]);
});
```

**Fix:** Add authentication middleware (e.g., JWT or session-based) and apply it to sensitive routes:

```js
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Unauthorized' });
  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch {
    res.status(403).json({ error: 'Forbidden' });
  }
}

// ✅ Protected route
app.get('/users', requireAuth, (req, res) => { ... });
```

---

### 🟠 High

#### 2. Security Misconfiguration — Missing Security Headers (OWASP A05)

No security-related HTTP headers are set. This leaves the app vulnerable to clickjacking, MIME-type sniffing, XSS, and more.

**Fix:** Add [`helmet`](https://helmetjs.github.io/):

```js
const helmet = require('helmet');
app.use(helmet());
// Sets: X-Frame-Options, X-Content-Type-Options, HSTS,
//       Content-Security-Policy, X-DNS-Prefetch-Control, etc.
```

#### 3. No Rate Limiting — DoS / Brute-Force Exposure (OWASP A04)

There is no rate limiting on any endpoint. An attacker can hammer the server with unlimited requests, enabling brute-force attacks and denial-of-service.

**Fix:** Use [`express-rate-limit`](https://github.com/express-rate-limit/express-rate-limit):

```js
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});

app.use(limiter); // Apply globally
```

#### 4. No CORS Policy (OWASP A05)

Express has no default CORS restrictions. If this API is consumed by a browser, cross-origin requests from any domain are permitted.

**Fix:** Explicitly configure CORS:

```js
const cors = require('cors');

app.use(cors({
  origin: ['https://yourdomain.com'], // allowlist specific origins
  methods: ['GET', 'POST'],
  allowedHeaders: ['Content-Type', 'Authorization'],
}));
```

---

### 🟡 Medium

#### 5. Information Disclosure — Verbose Error Responses (OWASP A09)

There is no global error handler. Express's default error handler will expose stack traces and internal details to clients when unhandled errors occur.

**Fix:** Add a catch-all error handler as the **last** middleware:

```js
